mapper.select:
SELECT 
FROM user_follow
WHERE follower_id = #{followerId}
  AND followee_id = #{followeeId}
LIMIT 1

mapper.update:
UPDATE user_follow
SET
    follower_id = #{followerId},
    followee_id = #{followeeId},
    create_time = #{createTime}
WHERE id = #{id}

mapper.delete:
DELETE FROM user_follow
WHERE follower_id = #{followerId}
  AND followee_id = #{followeeId}
